mapper.select:
select distinct m.menu_id, m.parent_id, m.menu_name, m.router_path, m.component, m.query_param, m.route_name, m.menu_status, ifnull(m.perms,'') as perms, m.is_frame, m.is_cache, m.menu_type, m.icon, m.order_num, m.create_time from sys_menu m left join sys_role_menu rm on m.menu_id = rm.menu_id left join sys_user_role ur on rm.role_id = ur.role_id left join sys_role ro on ur.role_id = ro.role_id where ur.user_id = #{params.userId}
AND m.menu_name like concat('%', #{menuName}, '%')
AND m.menu_status = #{menuStatus}
order by m.parent_id, m.order_num

select count(1)
from sys_menu
where parent_id = #{menuId}
